const entry = $('WhatsApp Webhook').first().json.body.entry[0].changes[0].value;
const message = entry.messages[0];
const messageType = message.type;
const phone = message.from;

if (messageType !== 'text') {
  return [{
    json: {
      isText: false,
      phone: phone,
      type: messageType,
      reply: "Sorry, I can only process text messages right now. 😊 Please type your query and I'll be happy to help!"
    }
  }];
}

return [{
  json: {
    isText: true,
    phone: phone,
    type: 'text',
    message: message.text.body
  }
}];

const phone = $('Check Message Type').first().json.phone;
const currentMessage = $('Check Message Type').first().json.message;

const names = ['Raj','Priya','Amit','Neha','Rahul','Pooja','Vikram','Anjali'];
const nameIndex = phone.split('').reduce((sum,c) => sum+c.charCodeAt(0),0) % names.length;
const agentName = names[nameIndex];

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};
if (!staticData.lastBookings) staticData.lastBookings = {};

const history = (staticData.conversations[phone] || [])
  .filter(m => m.message && m.message.trim().length > 0)
  .slice(-10);

let budget = '', carInterest = '', bookingStage = 'initial';
const historyText = history.map(m => m.message).join(' ').toLowerCase();
const bm = historyText.match(/(\d+[\s]*(?:lakh|lac|k|thousand|crore))/);
if (bm) budget = bm[0];
const carBrands = ['maruti','swift','baleno','dzire','wagon','alto','celerio','ignis','ertiga','brezza','vitara','xl6','ciaz','spresso','honda','city','amaze','elevate','jazz','hyundai','creta','i20','venue','verna','aura','alcazar','tucson','ioniq','kona','tata','nexon','harrier','safari','punch','altroz','tiago','tigor','curvv','mahindra','scorpio','xuv','bolero','thar','marazzo','toyota','innova','fortuner','glanza','hyryder','kia','seltos','sonet','carens','ev6','volkswagen','virtus','taigun','skoda','slavia','kushaq','mg','hector','astor','windsor','comet','zsev','jeep','compass','meridian','wrangler','renault','kiger','kwid','triber','duster','nissan','magnite','kicks','bmw','audi','mercedes','volvo','lexus','jaguar','land rover','porsche','citroen','isuzu','byd','force'];
for (const b of carBrands) { if (historyText.includes(b)) { carInterest = b; break; } }
if (historyText.includes('test drive') || historyText.includes('book')) bookingStage = 'booking';
else if (historyText.includes('price') || historyText.includes('cost') || historyText.includes('budget')) bookingStage = 'qualification';
else if (history.length > 0) bookingStage = 'conversation';

const isFirstMessage = history.length === 0;

const today = new Date();
const todayStr = today.toLocaleDateString('en-IN', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Asia/Kolkata'
});

const lastBooking = staticData.lastBookings[phone];
const lastBookingInfo = lastBooking
  ? `CUSTOMER'S LAST CONFIRMED BOOKING: Car = ${lastBooking.car}, Date = ${lastBooking.date}, Time = ${lastBooking.time}. Use this when customer asks about their booking status.`
  : `No previous booking on record for this customer.`;

const greetingWords = ['hi','hello','hey','hii','helo','namaste','hola','sup','yo','hai','hei'];
const isPureGreeting = greetingWords.includes(currentMessage.trim().toLowerCase());

const systemPrompt = `You are ${agentName}, a friendly sales agent at Handysolver Car Dealership.
Today is ${todayStr}.

${lastBookingInfo}

CRITICAL RULES:
1. ${isFirstMessage ? `FIRST message — say: "Hi! I'm ${agentName} from Handysolver Car Dealership 🚗 Welcome! How can I help you today?"` : `NOT first message. NEVER say hello or re-introduce yourself. Continue naturally.`}
2. Context: Budget=${budget||'not mentioned'}, Car Interest=${carInterest||'not mentioned'}, Stage=${bookingStage}
3. SHORT replies (2-4 lines). Conversational. No bullet points unless listing cars.
4. Respond in same language as customer (Hindi/Hinglish/English).
5. ${isPureGreeting ? `OVERRIDE EVERYTHING: Customer sent a greeting. Reply ONLY: "Hello! How can I help you today? 😊" — Nothing about test drive or cars unless they ask. Return booking: {"car":null,"date":null,"time":null} and stage: "other".` : `If customer sends only a greeting (hi/hello/hey/namaste) — respond warmly and ask how you can help. Do NOT jump to test drive or booking.`}

INVENTORY:
We are a multi-brand dealership stocking ALL popular cars available in India across every segment and brand — Maruti Suzuki, Hyundai, Tata, Honda, Kia, Toyota, Mahindra, MG, Skoda, Volkswagen, Renault, Nissan, Jeep, Citroen, Isuzu, BYD, BMW, Audi, Mercedes-Benz, Volvo, and more. New and used cars both available.

PRICE RANGES BY SEGMENT:
- Hatchbacks: ₹3.5L–11L (Alto, Swift, i20, Altroz, Baleno, Wagon R, Tiago, Kwid etc.)
- Micro SUVs: ₹6L–15L (Punch, Magnite, Kiger, XUV 3XO etc.)
- Sedans: ₹6.5L–19L (Dzire, City, Verna, Amaze, Slavia, Virtus etc.)
- Compact SUVs: ₹8L–22L (Nexon, Brezza, Venue, Sonet, Elevate, Kushaq, Taigun, Compass etc.)
- Mid SUVs: ₹11L–25L (Creta, Seltos, Alcazar, Hector, Astor, Grand Vitara etc.)
- Large SUVs: ₹13L–40L (Harrier, Safari, Scorpio N, Thar, Fortuner, Tucson etc.)
- MPVs: ₹6L–30L (Ertiga, Carens, Innova Crysta, Innova HyCross, XL6, Triber etc.)
- Electric: ₹7L–65L+ (Tiago EV, Punch EV, Nexon EV, Windsor EV, ZS EV, Ioniq 5, EV6, BYD Atto 3 etc.)
- Luxury: ₹45L–2Cr+ (BMW, Audi, Mercedes, Volvo, Jaguar, Porsche etc.)
- Used Cars: Starting ₹2L

INVENTORY RULE: Since we stock all popular Indian cars, NEVER say a car is unavailable unless it is not sold in India at all. Use your knowledge of Indian car prices and variants to answer accurately. EMI, exchange, and insurance available on all cars.

BOOKING RULES:
6. Set booking.car, booking.date, booking.time to non-null ONLY when customer provides ALL THREE in their CURRENT message — car model + specific date (DD-MM-YYYY) + time slot.
7. When customer agrees to test drive → ask: "Perfect! What date works for you, and what time? We're available any time between 9am–9pm 😊"
8. When customer gives relative date (tomorrow, next Monday etc.) → calculate exact date from today (${todayStr}) and confirm.
9. CONFIRMATION: Any affirmative response counts as YES — yes, haan, ok, sure, absolutely, correct, right, exactly, perfect, definitely, of course, bilkul, theek hai, yep, yup, ha.
10. booking.date must ALWAYS be in DD-MM-YYYY format.
11. If date is in the past → say "That date has passed! Could you pick a future date? 😊"

STATUS & REPEAT SCENARIOS:
12. Status questions → use LAST CONFIRMED BOOKING info to answer.
13. Cancel request → say "I'll have our team cancel your booking. They'll contact you shortly."
14. Reschedule request → ask for new date/time only.

CUSTOMER HANDLING:
15. Angry/frustrated → "I completely understand your frustration, and I'm sorry for the inconvenience. 🙏"
16. Off-topic → "Ha ha! I wish I could help with that 😄 But I'm your car expert!"
17. Budget under ₹3L → suggest used cars starting ₹2L.
18. NEVER say "Let me check" or "I'll look up" — answer confidently.
19. Business hours 9am–9pm. Outside hours → ask for a slot between 9am–9pm.

OUTPUT RULES — CRITICAL:
- Return valid JSON only. No extra text.
- Format: {"message":"reply here","stage":"initial|qualification|recommendation|booking|confirmed|other","booking":{"car":null,"date":null,"time":null}}
- stage = "confirmed" ONLY when setting all three booking fields to non-null.
- booking.time format: "9am", "10am", "11am", "12pm", "1pm" etc. NEVER 24-hour format.
- For ALL other messages booking must be: {"car":null,"date":null,"time":null}`;

const messages = [{ role: 'system', content: systemPrompt }];
for (const msg of history) {
  messages.push({ role: msg.role === 'assistant' ? 'assistant' : 'user', content: msg.message });
}
messages.push({ role: 'user', content: currentMessage });

return [{
  json: {
    model: "llama-3.1-8b-instant",
    messages: messages,
    temperature: 0.3,
    max_tokens: 300,
    response_format: { type: "json_object" }
  }
}];

try {
  const raw = $('Gemini AI').first().json;

  if (!raw.choices || !raw.choices[0] || !raw.choices[0].message) {
    return [{ json: { message: "I'm a bit busy right now, please send your message again! 🙏", booking: null, hasBooking: false, stage: 'error' } }];
  }

  const responseText = raw.choices[0].message.content || '';
  let parsed;

  try {
    parsed = JSON.parse(responseText);
  } catch(e) {
    const match = responseText.match(/\{[\s\S]*\}/);
    if (match) {
      try { parsed = JSON.parse(match[0]); }
      catch(e2) { return [{ json: { message: responseText.replace(/[\x00-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim(), booking: null, hasBooking: false, stage: 'other' } }]; }
    } else {
      return [{ json: { message: responseText.replace(/[\x00-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim(), booking: null, hasBooking: false, stage: 'other' } }];
    }
  }

  const message = (parsed.message || "Sorry, I couldn't process that. Please try again!")
    .replace(/[\x00-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();

  const booking = parsed.booking || null;
  const currentMsg = ($('Check Message Type').first().json.message || '').toLowerCase().trim();

  const greetingWords = ['hi','hello','hey','hii','helo','namaste','hola','sup','yo','hai'];
  const isPureGreeting = greetingWords.includes(currentMsg);

  const noBookingPhrases = [
    'was booking', 'kya booking', 'booking done', 'booking hua', 'booking huyi',
    'book ho gayi', 'book hua', 'book huyi', 'check booking', 'booking ho gayi',
    'pahle booking', 'pichhli booking', 'previous booking', 'booking check',
    'kya pichhli', 'booking huyi thi', 'was my booking', 'is my booking',
    'booking status', 'meri booking', 'booking confirm hui'
  ];

  const isSafetyBlock = isPureGreeting || noBookingPhrases.some(phrase => currentMsg.includes(phrase));
  const hasBooking = !isSafetyBlock && !!(booking && booking.car && booking.date && booking.time);

  return [{ json: { message, booking: hasBooking ? booking : null, hasBooking, stage: parsed.stage || 'other' } }];

} catch(e) {
  return [{ json: { message: "Sorry, something went wrong. Please try again!", booking: null, hasBooking: false, stage: 'error' } }];
}

const phone = $('Check Message Type').first().json.phone;
const userMessage = $('Check Message Type').first().json.message;
const aiResponse = $('Parse Response').first().json.message;
const stage = $('Parse Response').first().json.stage;
const booking = $('Parse Response').first().json.booking;

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};
if (!staticData.lastBookings) staticData.lastBookings = {};
if (!staticData.conversations[phone]) staticData.conversations[phone] = [];

staticData.conversations[phone].push({ role: 'user', message: userMessage });
staticData.conversations[phone].push({ role: 'assistant', message: aiResponse });

if (staticData.conversations[phone].length > 40) {
  staticData.conversations[phone] = staticData.conversations[phone].slice(-40);
}

if (stage === 'confirmed' && booking && booking.car && booking.date && booking.time) {
  staticData.lastBookings[phone] = {
    car: booking.car,
    date: booking.date,
    time: booking.time,
    confirmedAt: new Date().toISOString()
  };
  staticData.conversations[phone] = staticData.conversations[phone].slice(-6);
}

return [{ json: { saved: true, historyLength: staticData.conversations[phone].length } }];
